queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasGenres ?child ; p:hasMusic_Critics ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Music_Critics } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasGenres ?child ; p:hasMusic_Critics ?parent . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Music_Critics } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?name2 WHERE {
  ?music_critics_genres a :Music_Critics_Genres .
  ?genres a :Genres .
  ?music_critics_genres p:hasGenres ?genres .
  ?music_critics a :Music_Critics .
  ?music_critics_genres p:hasMusic_Critics ?music_critics .
  ?music_critics p:name ?name .
  ?genres p:name ?name2 .
} }
}
